<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>

    <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
        <div role="document" class="modal-dialog" style="max-width: 1200px !important;">
            <div class="modal-content">

                <!-- HEADER -->
                <div class="modal-header theme-primary partition-full d-flex">
                    <h4 class="modal-title">{{ $t('CloneSetup') }}</h4>
                    <button type="button" class="close" @click="Close">
                        <em class="fa fa-times"></em>
                    </button>
                </div>

                <!-- BODY -->
                <div class="modal-body">

                    <!-- SEARCH -->
                    <div class="row mb-2">
                        <dynamic-form lang="en" ref="CloneSetup" :buttons="buttons"  :schema="FormSchema" 
                         v-on:OnSubmit="SubmitData" :mandatorytext="$t('MandatoryString')">
                      </dynamic-form>
                        
                    </div>

                    <!-- TABLE -->
     
                 </div>
            </div>
        </div>
    </div>
</div>
</template>


<script>
import DataService from '../../services/DataService';
export default {
    props: {
        ClientId: {
            type: Number,
            required: true,
        },
    },
    data() {
        return {
            isLoading: false,
            isShown: false,
            contractName:'',
            clientList:[],
            isFetchingClients: false,
            BillerItemsList:[],
            UserId:'',
            UtilityIds:'',
            receivedData: [],   // ✅ REQUIRED
            CloneSetupList: [
                {
                    isBillingRule: false,
                    isCDCMapping: false,
                    isCompanyHoliday: false,
                    isInvoiceGrouping: false,
                    isRateSchedule: false,
                    isSBA: false,
                    isTalygenUtility: false
                }
            ],           
            FormSchema: [
                {   
                    
                    layoutType: "double",
                    Data: [                      
                            {
                                astype: "SearchableSelectField",
                                label: this.$t('ContractCompanyName'),
                                name: "ContractName",
                                value: "",
                                placeholder: "Select",
                                visibility: true,
                                isSearch: false,
                                config: {
                                    options: [],
                                    actionButtons: {
                                        selectAll: false,
                                        active: false,
                                        inactive: false,
                                        clear: false
                                    },
                                    isMultiple: false,
                                    groupFields: ['groupText'],
                                    minSearchLength: 0,
                                    statusFieldConfig: {
                                        fieldName: 'status',
                                        activeValues: ['Active', 'active'],
                                        inactiveValues: ['Inactive', 'inactive'],
                                        activeColor: '#28a745',
                                        inactiveColor: '#dc3545'
                                    },
                                    onChange: null
                                },
                                disabled: false,
                                validationRules: {
                                    "required": true
                                },
                            },                    
                        

                    ],
                },{
                    group_name: this.$t('ContractSetup'),
                    layoutType: "four",
                    Data: [
                         {
                            astype: "toggleField",
                            label: this.$t('Talygen Utility'),
                            name: "isTalygenUtility",
                            value: true
                        },                                       
                        {
                            astype: "toggleField",
                            label: this.$t('Rate Schedule'),
                            name: "isRateSchedule",
                            value: false
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Billing Rule'),
                            name: "isBillingRule",
                            value: false
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Invoice Grouping'),
                            name: "isInvoiceGrouping",
                            value: false
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('CDC Mapping'),
                            name: "isCDCMapping",
                            value: false
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('Company Holiday'),
                            name: "isCompanyHoliday",
                            value: false
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('SBA'),
                            name: "isSBA",
                            value: false
                        },
                       
                    ],

                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.CreateClone
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.Close,
                },
            ],           
        }
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    created: async function () {
        debugger;
        var vm = this;
        vm.UserId=vm.GetUserInfo.ID;
        await vm.GetDDLCompanyContractClients();    
        await vm.FetchData();    
        vm.FormSchema[0].Data[0].value=vm.ClientId;       
    },
    methods: {
         GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await DataService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                debugger
                vm.$refs.CloneSetup.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.CloneSetup.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.$refs.CloneSetup.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.CloneSetup.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },  
        
        FetchData: async function () {
            const vm = this;
            const url = `clientId=${vm.ClientId}&utilityIds=${vm.UtilityIds}`;

            DataService.CopyClientSetup(url).then(response => {
                if (response.status === 200 && Array.isArray(response.data)) {

                    const item = response.data[0]; // assuming single record

                    const fields = vm.FormSchema[1].Data;

                    // Utility
                    fields[0].label = `Utility (${item.TalygenUtilityRecordsCount})`;
                    fields[0].customClass = item.TalygenUtilityRecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';

                    // Rate Schedule
                    fields[1].label = `Rate Schedule (${item.RateScheduleRecordsCount})`;
                    fields[1].customClass = item.RateScheduleRecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';

                    // Billing Rules
                    fields[2].label = `Billing Rules (${item.BillingRulesRecordsCount})`;
                    fields[2].customClass = item.BillingRulesRecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';

                    // Invoice Grouping
                    fields[3].label = `Invoice Grouping (${item.InvoiceGroupingRecordsCount})`;
                    fields[3].customClass = item.InvoiceGroupingRecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';

                    // CDC Mapping
                    fields[4].label = `CDC Mapping (${item.CDCMappingRecordsCount})`;
                    fields[4].customClass = item.CDCMappingRecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';

                    // Company Holiday
                    fields[5].label = `Company Holiday (${item.CompanyHolidayRecordsCount})`;
                    fields[5].customClass = item.CompanyHolidayRecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';

                    // SBA
                    fields[6].label = `SBA (${item.SBARecordsCount})`;
                    fields[6].customClass = item.SBARecordsCount > 0
                        ? 'label-green'
                        : 'label-grey';
                }
            });
        },   

        SubmitData(formfields, val) {
            const vm = this;

            // 🔹 counts captured from FetchData()
            const counts = vm.ClientItemsList || {};

            // 1️⃣ Build CloneSetupList (flags + counts)
            vm.CloneSetupList = [{
                contractName: formfields.ContractName,

                // ✅ toggle values
                isTalygenUtility: formfields.isTalygenUtility,
                isRateSchedule: formfields.isRateSchedule,
                isBillingRule: formfields.isBillingRule,
                isInvoiceGrouping: formfields.isInvoiceGrouping,
                isCDCMapping: formfields.isCDCMapping,
                isCompanyHoliday: formfields.isCompanyHoliday,
                isSBA: formfields.isSBA,

                // ✅ counts
                TalygenUtilityRecordsCount: counts.TalygenUtilityRecordsCount || 0,
                RateScheduleRecordsCount: counts.RateScheduleRecordsCount || 0,
                BillingRulesRecordsCount: counts.BillingRulesRecordsCount || 0,
                InvoiceGroupingRecordsCount: counts.InvoiceGroupingRecordsCount || 0,
                CDCMappingRecordsCount: counts.CDCMappingRecordsCount || 0,
                CompanyHolidayRecordsCount: counts.CompanyHolidayRecordsCount || 0,
                SBARecordsCount: counts.SBARecordsCount || 0
            }];

            // 2️⃣ Ask for confirmation
            vm.confirmR(vm.$t("ConfirmAlreadyExistsCLientSetupOption"), true, vm.$t("Move"),
                {
                    yes: vm.$t("Yes"),
                    no: vm.$t("No")
                }
            ).then(isConfirmed => {
                // 3️⃣ Build payload AFTER confirmation
                const payload = {
                    fromClientId: vm.ClientId,
                    targetClientId: formfields.ContractName,
                    cloneClientSetup: JSON.stringify(vm.CloneSetupList), // ✅ flags + counts
                    utilityIds: vm.UtilityIds,
                    cloneType: "Move",
                    confirmDeleteType: isConfirmed ? "YES" : "NO"
                };

                vm.isLoading = true;

                // 4️⃣ Save
                DataService.SaveCloneSetup(JSON.stringify(payload))
                    .then(response => {
                        const status = response?.data?.status || response?.data?.Status;

                        if (status === "Success") {
                            //vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Contract')]),"success",true,vm.$t('Alert'));
                            vm.ShowAlert(vm.$t('ContractSetupSuccess', [vm.$t('Contract')]),"success",true,vm.$t('Alert'));
                            vm.$parent.FetchData(); // refresh counts
                            vm.Close();
                        } else {
                            vm.ShowAlert(vm.$t("ErrorWhileSaving"),"danger",true,vm.$t("Alert"));
                        }
                    })
                    .finally(() => {
                        vm.isLoading = false;
                    });
            });
        },
        Close: function () {
            this.$parent.CloneSetupPopup = false;
        }
    }
}
</script>

